// 二分答案法
fast<int> f;
vector<int> g[N], ng[N];
bool vis[N];
int dis[N];
void solve(int CASE)
{
	int n = f.in(), m = f.in(), k = f.in();
	fa(i, 1, m) {
		int u = f.in(), v = f.in();
		g[u].pb(v), g[v].pb(u);
	}

	// 多源最短路，找火焰蔓延到 i 的最短时间
	fa(i, 1, n)dis[i] = INF;
	var Q = queue<pii>();
	fa(i, 1, k) {
		int x = f.in();
		Q.push({ x,0 });
		dis[x] = 0;
	}
	while (Q.size()) {
		var[now, d] = Q.front();
		Q.pop();
		if (d > dis[now])continue;
		for (int to : g[now]) {
			if (dis[to] > dis[now] + 1) {
				dis[to] = dis[now] + 1;
				Q.push({ to,dis[to] });
			}
		}
	}

	// 直接二分答案，利用 dis 建新图后，找环解决即可
	var check = [&](int mid)->bool {
		fa(i, 1, n)ng[i].clear();
		fa(now, 1, n) {
			for (int to : g[now]) {
				int d = max(dis[now], dis[to]);
				if (d <= mid)ng[now].pb(to);
			}
		}
		fa(i, 1, n)vis[i] = 0;
		var dfs = [&](var dfs, int now, int fa)->bool {
			vis[now] = 1;
			for (int to : ng[now]) {
				if (to == fa)continue;
				if (vis[to])return 1;
				else {
					if (dfs(dfs, to, now))return 1;
				}
			}
			return 0;
			};
		fa(i, 1, n)if (!vis[i]) {
			if (dfs(dfs, i, 0))return 1;
		}
		return 0;
		};
	int l = 0, r = n, ans = -1;
	while (l <= r) {
		int mid = l + r >> 1;
		if (check(mid)) {
			r = mid - 1;
			ans = mid;
		}
		else l = mid + 1;
	}

	if (ans == -1)cout << "Poor D!" << endl;
	else cout << ans << endl;
	return;
}

// 并查集法
fast<int> f;
vector<int> g[N];
int dis[N], s[N];
int find(int x) {
	if (s[x] == x)return x;
	return s[x] = find(s[x]);
}
void solve(int CASE)
{
	int n = f.in(), m = f.in(), k = f.in();
	fa(i, 1, m) {
		int u = f.in(), v = f.in();
		g[u].pb(v), g[v].pb(u);
	}

	// 多源最短路，dis[i]：火焰蔓延到 i 的最短时间
	// 过程中进行类似 Kruskal 算法枚举边
	int ans = INF;
	fa(i, 1, n)dis[i] = -1, s[i] = i;
	var Q = queue<int>();
	fa(i, 1, k) {
		int x = f.in();
		if (dis[x] == -1) { // 处理重复
			Q.push(x);
			dis[x] = 0;
		}
	}

	while (Q.size()) {
		int now = Q.front();
		Q.pop();

		if (dis[now] >= ans)break; // 剪枝

		int e1 = find(now);
		for (int to : g[now]) {
			if (dis[to] == -1) {
				// to 节点未燃烧
				dis[to] = dis[now] + 1;
				Q.push(to);
				int e2 = find(to);
				s[e2] = e1;
			}
			else {
				// to 节点已燃烧
				// 防止 now - to 这条边重复，这边利用 dis 的层级关系进行处理
				// 这样每条边都只处理一次，就像 Kruskal 算法枚举边一样
				if (dis[to] > dis[now] or dis[now] == dis[to] and now < to) {
					int e2 = find(to);
					if (e1 == e2) {
						int res = max(dis[now], dis[to]);
						ans = min(ans, res);
					}
					else s[e2] = e1;
				}
			}
		}
	}

	if (ans == INF)cout << "Poor D!" << endl;
	else cout << ans << endl;
	return;
}
